What does this program print?

```cpp
#include <iostream>
int main() {
    int i{3};
    do {
        std::cout << i << "\n";
        --i;
    } while (i > 3);
    return 0;
}
```

This program should keep asking for a number until the user enters something in the range 1–5, then print it. What is wrong?

```cpp
#include <iostream>
int main() {
    do {
        int n{};
        std::cout << "Enter 1-5: ";
        std::cin >> n;
    } while (n < 1 || n > 5);
    return 0;
}
```

What does this program print?

```cpp
#include <iostream>
int main() {
    int x{0};
    do {
        x += 2;
    } while (x < 6);
    std::cout << x << "\n";
    return 0;
}
